347	/// Resolves unsuffixed numeric operands for binary operations by inferring types based on the other operand, the
348	/// operation type, and an optional expected type. Handles special cases for multiplication and exponentiation with
349	/// additional logic for `Group`, `Scalar`, and `Field` type inference. Ensures that both operands are resolved to
350	/// compatible types before evaluation. Returns a tuple of resolved `Value`s or an error if resolution fails.
351	fn resolve_unsuffixed_binary_op_operands(
352	    lhs: &Value,
353	    rhs: &Value,
354	    op: &BinaryOperation,
355	    expected_ty: &Option<Type>,
356	    span: &Span,
357	) -> Result<(Value, Value)> {
358	    use Type::*;
359	
360	    let lhs_ty = lhs.get_numeric_type();
361	    let rhs_ty = rhs.get_numeric_type();
362	
363	    Ok(match op {
364	        BinaryOperation::Mul => {
365	            // For a `Mul`, if on operand is a Scalar, then the other must ba a `Group`. Otherwise, both ops must have
366	            // the same type as the return type of the multiplication.
367	            let lhs = match rhs_ty {
368	                Some(Group) => lhs.resolve_if_unsuffixed(&Some(Scalar), *span)?,
369	                Some(Scalar) => lhs.resolve_if_unsuffixed(&Some(Group), *span)?,
370	                _ => lhs.resolve_if_unsuffixed(&rhs_ty, *span)?.resolve_if_unsuffixed(expected_ty, *span)?,
371	            };
372	
373	            let rhs = match lhs_ty {
374	                Some(Group) => rhs.resolve_if_unsuffixed(&Some(Scalar), *span)?,
375	                Some(Scalar) => rhs.resolve_if_unsuffixed(&Some(Group), *span)?,
376	                _ => rhs.resolve_if_unsuffixed(&lhs_ty, *span)?.resolve_if_unsuffixed(expected_ty, *span)?,
377	            };
378	
379	            (lhs, rhs)
380	        }
381	        BinaryOperation::Pow => {
382	            // For a `Pow`, if one operand is a `Field`, then the other must also be a `Field.
383	            // Otherwise, only the `lhs` must match the return type.
384	            let lhs_resolved = lhs
385	                .resolve_if_unsuffixed(&rhs_ty.filter(|ty| matches!(ty, Type::Field)), *span)?
386	                .resolve_if_unsuffixed(expected_ty, *span)?;
387	
388	            let rhs_resolved = rhs.resolve_if_unsuffixed(&lhs_ty.filter(|ty| matches!(ty, Type::Field)), *span)?;
389	
390	            (lhs_resolved, rhs_resolved)
391	        }
392	        _ => (
393	            lhs.resolve_if_unsuffixed(&rhs_ty, *span)?.resolve_if_unsuffixed(expected_ty, *span)?,
394	            rhs.resolve_if_unsuffixed(&lhs_ty, *span)?.resolve_if_unsuffixed(expected_ty, *span)?,
395	        ),
396	    })
397	}
