965	// SnarkVM will not parse fields, groups, or scalars with leading zeros, so we strip them out.
966	fn prepare_snarkvm_string(s: &str, suffix: &str) -> String {
967	    // If there's a `-`, separate it from the rest of the string.
968	    let (neg, rest) = s.strip_prefix("-").map(|rest| ("-", rest)).unwrap_or(("", s));
969	    // Remove leading zeros.
970	    let mut rest = rest.trim_start_matches('0');
971	    if rest.is_empty() {
972	        rest = "0";
973	    }
974	    format!("{neg}{rest}{suffix}")
