27	    TypeChecking,
28	    TypeCheckingInput,
29	    Unrolling,
30	};
31	
32	use leo_ast::Node;
33	use leo_errors::{CompilerError, Result};
34	
35	/// Pass that runs const propagation, loop unrolling, and monomorphization until a fixed point.
36	pub struct ConstPropUnrollAndMorphing;
37	
38	impl Pass for ConstPropUnrollAndMorphing {
39	    type Input = TypeCheckingInput;
40	    type Output = ();
41	
42	    const NAME: &str = "ConstantPropogation+LoopUnrolling+Monomorphization";
43	
44	    fn do_pass(input: Self::Input, state: &mut CompilerState) -> Result<Self::Output> {
45	        const LARGE_LOOP_BOUND: usize = 1024usize;
46	
47	        for _ in 0..LARGE_LOOP_BOUND {
48	            let loop_unroll_output = Unrolling::do_pass((), state)?;
49	
50	            let const_prop_output = ConstPropagation::do_pass((), state)?;
51	
52	            let remove_unreachable_output = RemoveUnreachable::do_pass((), state)?;
53	
54	            let monomorphization_output = Monomorphization::do_pass((), state)?;
55	
56	            // Clear the symbol table and create it again. This is important because after all the passes above run, the
57	            // program may have changed significantly (new functions may have been added, some functions may have been
58	            // deleted, etc.) We do want to retain evaluated consts, so that const propagation can tell when it has evaluated a new one.
59	            state.symbol_table.reset_but_consts();
60	            GlobalVarsCollection::do_pass((), state)?;
61	            PathResolution::do_pass((), state)?;
62	            GlobalItemsCollection::do_pass((), state)?;
63	
64	            // Now run the type checker again to validate and infer types. Again, this is important because the program
65	            // may have changed significantly after the passes above.
66	            TypeChecking::do_pass(input.clone(), state)?;
67	
68	            if !const_prop_output.changed
69	                && !loop_unroll_output.loop_unrolled
70	                && !monomorphization_output.changed
71	                && !remove_unreachable_output.changed
72	            {
73	                // We've reached a fixed point. Verify interface conformance now that const propagation,
74	                // loop unrolling, and monomorphization have fully converged.
75	                CheckInterfaces::do_pass((), state)?;
76	
77	                // See if we have any errors.
78	                if let Some(not_evaluated_span) = const_prop_output.const_not_evaluated {
