390	    fn reconstruct_iteration(&mut self, _input: IterationStatement) -> (Statement, Self::AdditionalOutput) {
391	        panic!("`IterationStatement`s should not be in the AST at this point.");
392	    }
393	
394	    fn reconstruct_return(&mut self, input: ReturnStatement) -> (Statement, Self::AdditionalOutput) {
395	        let (expression, statements) = self.reconstruct_expression(input.expression, &());
396	        (ReturnStatement { expression, ..input }.into(), statements)
397	    }
398	
399	    fn reconstruct_conditional(&mut self, input: leo_ast::ConditionalStatement) -> (Statement, Self::AdditionalOutput) {
400	        let (condition, mut statements) = self.reconstruct_expression(input.condition, &());
401	        let (then, statements2) = self.reconstruct_block(input.then);
402	        statements.extend(statements2);
403	        let otherwise = input.otherwise.map(|oth| {
404	            let (expr, statements3) = self.reconstruct_statement(*oth);
405	            statements.extend(statements3);
406	            Box::new(expr)
407	        });
408	        (ConditionalStatement { condition, then, otherwise, ..input }.into(), statements)
409	    }
