17	use crate::CompilerState;
18	
19	use leo_ast::{
20	    ArrayAccess,
21	    AssignStatement,
22	    AstVisitor,
23	    DefinitionPlace,
24	    DefinitionStatement,
25	    Expression,
26	    Identifier,
27	    IntegerType,
28	    Literal,
29	    MemberAccess,
30	    Node as _,
31	    Path,
32	    Program,
33	    Statement,
34	    Stub,
35	    Type,
